beta0=[0, 0, 0, 30.0, 0]

def lmap(*cargs):
    return list(map(*cargs))

def f_new_sphere3(beta, x):
    b = numpy.matrix(lmap(lambda a, b : a - b, x[:3], beta[:3]))
    m = list(numpy.array(b.transpose()))
    r0 = lmap(lambda y : beta[3] - vector.norm(y), m)
    #r0 = lmap(lambda y : 1 - vector.norm(y)/beta[3], m)
    g = list(numpy.array(numpy.matrix(x[3:]).transpose()))
    fac = 1 # weight deviation
    def dip(y, z):
        n = min(max(vector.dot(y, z)/vector.norm(y), -1), 1)
        return n
    r1 = lmap(lambda y, z : fac*beta[3]*(beta[4]-dip(y, z)), m, g)

    return r0 + r1

def minpack_f(beta, fvec):
    r = f_new_sphere3(beta, zpoints)
    fvec[:] = r
    return 0

beta0 = numpy.array(beta0, dtype=float)
fvec = numpy.empty(len(2*zpoints[0]), dtype=float)

result = minpack.lmdif1(minpack_f, beta0, fvec)
if result in [1, 2, 3, 4]:
    print('minpack', beta0)

import odrpack

beta0= numpy.asarray([0, 0, 0, 30.0, 0], dtype=float)
xdata = numpy.asarray(zpoints, dtype=float)
ydata = numpy.zeros((2, xdata.shape[-1]), dtype=float)

def f_odrpack(x, beta):
    r = f_new_sphere3(beta, x)
    ret = numpy.asarray(r, dtype=float)
    ret = ret.reshape((2, -1))
    return ret

sol = odrpack.odr_fit(
    f_odrpack,
    xdata,
    ydata,
    beta0,
    task='implicit-ODR',
    maxit=1000,
)

if sol.success:
    print("odrpack", sol.beta)
